sp_angular_provider.script:
/* Use this Directive to show popover for a profile
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
		<div id="popoverWrapper" ng-mouseenter="c.avatarMouseEnter()" >
			<dtech-popover-profile dtech-param-object="data.popoverRecord" ng-mouseleave="c.avatarMouseLeave()"></dtech-popover-profile>
		</div>


	dtechParamObject maps to dtech-param-object

	Here are two ways to get the HTML for the directive to use:
	1. template: htmlTemplate
		var htmlTemplate = '<div>some simple html goes here</div>' + '<div> as a contactenated string</div'
	2. templateUrl: getTemplateUrl('x_153465_discovert_dtechPopoverProfile.html')
	    In UI Macros, create a new macro, remove default XML code and carefully write the desired HTML, lacks syntax checking for HTML.

//
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
// Script Continued Below
// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//  Renamed dtechGraphObjectPopover to the new name dtechPopoverProfile
//  Messages will be stored in object messages, added row3Message for Open Contact Page
// 2.8.1 | 2022-11-21 | mmcc | STRY0132316 - Tasker User Profile Page- Add Component Selector - User Settings Container Widget
//  Uncomment block of code for $scope.openUserProfileModal
//  Need to hide Message button, update $scope.connectEnabled = function() to force false
//										   
*/
function dtechPopoverProfile(getTemplateUrl, spModal, $window) {

    var jsController =
        function($scope) {

            // 			$scope.callPhone = function(phone) {
            // 				var phoneData = 'tel:' + phone.replace(/[^0-9]/g, '');
            // 				$window.open(phoneData, '_self');
            // 			}

            // From button X click added to UI Macros HTML 
            // 			$scope.closePopover = function() {
            // 				var popoverDiv = angular.element(document.getElementById('popoverWrapper'))[0];
            // 				popoverDiv.style.display = "none";
            // 				popoverDiv = undefined;
            // 			};

            // Example HTML <span class="dtech-avatar-link" ng-click="openUserProfileModal()"> Open Contact Page</span>
            // Import spModal
            $scope.openUserProfileModal = function() {
                spModal.open({
                    title: 'Tasker User Settings Container',
                    backdrop: 'static',
                    widget: 'tasker_user_settings_container',
                    widgetInput: {
                        sys_id: $scope.dtechParamObject.sys_id,
                        isModal: true
                    },
                    size: 'lg',
                    buttons: [],
                    footerStyle: {
                        'display': 'none'
                    }
                });
            };

            $scope.openUserProfileTab = function() {
                //$window.open($scope.dtechParamObject.contactPageHref, '_blank');
							// STRY0130623 - not sure why, but I think the macro didn't reload on all browsers and this link was still hit at times
							// for now, just sending the link over so people don't have to be told to refresh browser
							$scope.openUserProfileModal();
            };

            $scope.connectEnabled = function() {
                return false; // At this time do not show the button
                // return $scope.dtechParamObject.connectEnabled;
            };

            $scope.openConnectConversation = function() {
                $window.open('/$c.do#?user=' + $scope.dtechParamObject.liveProfileId, '_blank');
            };

            $scope.sendMailTo = function() {
                var emailData = 'mailto:' + $scope.dtechParamObject.email;
                if ($scope.dtechParamObject.messages.emailSubject && $scope.dtechParamObject.messages.emailSubject.length > 0) {
                    emailData = emailData + '?subject=' + $scope.dtechParamObject.messages.emailSubject;
                }

                $window.open(emailData, '_self');
            };
        };

    return {
        restrict: 'E',
        scope: {
            dtechParamObject: '<' // @: string 1 way, =: object 2 way, <: object 1 way
        },
        controller: jsController,
        templateUrl: getTemplateUrl('x_153465_discovert_dtechPopoverProfile.html')
    };
}
